const stripe = new Stripe(env.STRIPE_SECRET_KEY, {
  httpClient: Stripe.createFetchHttpClient() // CRITICAL: Workers use fetch, not Node http
});
const session = await stripe.checkout.sessions.create({
  mode: 'subscription',
  line_items: [{ price: env.STRIPE_PRICE_ID, quantity: 1 }],
  customer_email: body.email,
  success_url: 'https://nexus-alert.com/success?session_id={CHECKOUT_SESSION_ID}',
  cancel_url: 'https://nexus-alert.com/pricing',
  metadata: { email: body.email }
});
return new Response(JSON.stringify({ url: session.url }), { status: 200, headers: corsHeaders });
```

2. **POST /api/webhook** (backend/src/worker.js:~L75):
```javascript
const rawBody = await request.text(); // MUST read before any JSON parsing for signature verification
const sig = request.headers.get('stripe-signature');
const event = await stripe.webhooks.constructEventAsync(rawBody, sig, env.STRIPE_WEBHOOK_SECRET);

switch (event.type) {
  case 'checkout.session.completed':
    const session = event.data.object;
    await env.NEXUS_ALERTS_KV.put(
      `license:${session.metadata.email}`,
      JSON.stringify({
        status: 'premium',
        stripeCustomerId: session.customer,
        stripeSubscriptionId: session.subscription,
        activatedAt: new Date().toISOString(),
        tier: 'premium'
      })
    );
    break;
  case 'customer.subscription.deleted':
    const sub = event.data.object;
    const customer = await stripe.customers.retrieve(sub.customer);
    const licenseKey = `license:${customer.email}`;
    const existing = JSON.parse(await env.NEXUS_ALERTS_KV.get(licenseKey) || '{}');
    await env.NEXUS_ALERTS_KV.put(licenseKey, JSON.stringify({ ...existing, status: 'free', tier: 'free' }));
    break;
}
return new Response(JSON.stringify({ received: true }), { status: 200 });
```

