```javascript
async function checkAllSubscribers(env) {
  const { keys } = await env.NEXUS_ALERTS_KV.list({ prefix: 'subscriber:' });

  for (const { name: key } of keys) {
    const sub = JSON.parse(await env.NEXUS_ALERTS_KV.get(key));
    const license = JSON.parse(await env.NEXUS_ALERTS_KV.get(`license:${sub.email}`) ?? '{}');
    const tier = license.tier ?? 'free';

    // Free tier: enforce 30-minute cooldown
    if (tier === 'free' && sub.last_checked_at) {
      const elapsed = Date.now() - new Date(sub.last_checked_at).getTime();
      if (elapsed < 30 * 60 * 1000) {
        console.log(`Skipping ${sub.email} - free tier cooldown (${Math.floor(elapsed/1000)}s since last check)`);
        continue;
      }
    }

    // Premium tier: always check (no cooldown)
    const slots = await checkSlots(sub.locations, sub.program, sub.dateRange, sub.timeRange, env);

    if (slots.length > 0) {
      await sendEmailNotification(sub.email, slots, env);
      // SMS for premium users handled in Task 3
    }

    // Update last_checked_at for BOTH tiers
    sub.last_checked_at = new Date().toISOString();
    await env.NEXUS_ALERTS_KV.put(key, JSON.stringify(sub));
  }
}
```

3. **PUT /api/subscriber** (backend/src/worker.js:~L150):
