if (request.method === 'PUT' && pathname === '/api/subscriber') {
  const body = await request.json();
  const key = `subscriber:${body.email}`;
  const existing = await env.NEXUS_ALERTS_KV.get(key);

  if (!existing) {
    return new Response(JSON.stringify({ error: 'Subscriber not found' }), { status: 404, headers: corsHeaders });
  }

  const record = JSON.parse(existing);
  const updated = {
    ...record,
    locations: body.locations ?? record.locations,
    program: body.program ?? record.program,
    dateRange: body.dateRange ?? record.dateRange,
    timeRange: body.timeRange ?? record.timeRange,
    phone: body.phone ?? record.phone
    // tier NOT updatable here - only via Stripe webhook
  };

  await env.NEXUS_ALERTS_KV.put(key, JSON.stringify(updated));
  return new Response(JSON.stringify({ success: true }), { status: 200, headers: corsHeaders });
}
```

